import React from 'react'
// import uniqid from 'uniqid'
import { education } from '../../portfolio'
// import EducationContainer from '../EducationContainer/EducationContainer'
import './Education.css'

const Education = () => {
  if (!education.length) return null

  return (
    <section id='eduction' className='section education'>
      <h2 className='section__title'>Education</h2>

      <div className='education__grid'>
        <div className='education__school'> San Jose State University</div>
        <div className='education__degree'> Master&apos;s Degree </div>
        {/* <div className='education_school'> San Jose State University</div> */}
      </div>
    </section>
  )
}

export default Education
